terraform {
  required_providers {
    kubernetes = {
      source  = "hashicorp/kubernetes"
      version = "~> 2.35"
    }
  }
}

# --------------------------------------------------------------------------
# Namespace Resources (Task 3: AC 1)
# for_each over map to prevent resource reordering issues
# --------------------------------------------------------------------------

resource "kubernetes_namespace_v1" "namespaces" {
  for_each = var.namespaces

  metadata {
    name = each.key

    labels = {
      "environment"                = var.environment
      "managed-by"                 = "terraform"
      "business-area"              = each.key
    }

    annotations = {
      "instrumentation.opentelemetry.io/inject-python" = "true"
    }
  }
}

