    error_message = "ad_group_ops_object_id must be a valid UUID or empty string."
  }
}

variable "ad_group_admin_object_id" {
  description = "Azure AD group object ID for GRP-PYTHON-ADMIN (full cluster admin)"
  type        = string
  validation {
    condition     = var.ad_group_admin_object_id == "" || can(regex("^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$", var.ad_group_admin_object_id))
    error_message = "ad_group_admin_object_id must be a valid UUID or empty string."
  }
}

# --------------------------------------------------------------------------
# Resource Quota Defaults (AC 1)
# --------------------------------------------------------------------------

variable "default_cpu_request" {
  description = "Default CPU request quota per namespace (cores)"
  type        = string
  default     = "2"
}

variable "default_cpu_limit" {
  description = "Default CPU limit quota per namespace (cores)"
  type        = string
  default     = "4"
}

variable "default_memory_request" {
  description = "Default memory request quota per namespace"
  type        = string
  default     = "2Gi"
}

variable "default_memory_limit" {
  description = "Default memory limit quota per namespace"
  type        = string
  default     = "4Gi"
}

variable "default_max_pods" {
  description = "Default maximum pods per namespace (NFR16: 20 concurrent CronJobs)"
