# --------------------------------------------------------------------------
# RBAC Roles and Bindings (Task 5: AC 2, 3, 4, 5)
# AD group subjects use kind: Group with rbac.authorization.k8s.io apiGroup
# --------------------------------------------------------------------------

# --------------------------------------------------------------------------
# Task 5.1: Developer Role — own namespace only (AC 2)
# Uses RoleBinding (not ClusterRoleBinding) for namespace-scoped access
# --------------------------------------------------------------------------

resource "kubernetes_cluster_role_v1" "namespace_developer" {
  metadata {
    name = "namespace-developer"
  }

  rule {
    api_groups = [""]
    resources  = ["pods", "pods/log", "events", "configmaps"]
    verbs      = ["get", "list", "watch"]
  }

  rule {
    api_groups = ["batch"]
    resources  = ["jobs", "cronjobs"]
    verbs      = ["get", "list", "watch"]
  }
}

# Task 5.2: Per-namespace RoleBinding for DEV group
resource "kubernetes_role_binding_v1" "namespace_developer" {
  for_each = var.ad_group_dev_object_id != "" ? var.namespaces : {}

  metadata {
    name      = "developer-binding"
    namespace = kubernetes_namespace_v1.namespaces[each.key].metadata[0].name
  }

  role_ref {
    api_group = "rbac.authorization.k8s.io"
    kind      = "ClusterRole"
    name      = kubernetes_cluster_role_v1.namespace_developer.metadata[0].name
  }

  subject {
    kind      = "Group"
    name      = var.ad_group_dev_object_id
    api_group = "rbac.authorization.k8s.io"
  }
}

# --------------------------------------------------------------------------
# Task 5.3: Reviewer Role — read-only ALL namespaces (AC 3)
# Uses ClusterRoleBinding for cluster-wide read access
# --------------------------------------------------------------------------

resource "kubernetes_cluster_role_v1" "namespace_reviewer" {
  metadata {
    name = "namespace-reviewer"
  }

  rule {
    api_groups = [""]
    resources  = ["pods", "pods/log", "events", "configmaps", "namespaces"]
    verbs      = ["get", "list", "watch"]
  }

  rule {
    api_groups = ["batch"]
    resources  = ["jobs", "cronjobs"]
    verbs      = ["get", "list", "watch"]
  }
}

# Task 5.4: ClusterRoleBinding for REVIEW group
resource "kubernetes_cluster_role_binding_v1" "namespace_reviewer" {
  count = var.ad_group_review_object_id != "" ? 1 : 0

  metadata {
    name = "reviewer-binding"
  }

  role_ref {
    api_group = "rbac.authorization.k8s.io"
    kind      = "ClusterRole"
    name      = kubernetes_cluster_role_v1.namespace_reviewer.metadata[0].name
  }

  subject {
    kind      = "Group"
    name      = var.ad_group_review_object_id
    api_group = "rbac.authorization.k8s.io"
  }
}

# --------------------------------------------------------------------------
# Task 5.5: Ops Role — view, logs, exec ALL namespaces (AC 4)
# --------------------------------------------------------------------------

resource "kubernetes_cluster_role_v1" "namespace_ops" {
  metadata {
    name = "namespace-ops"
  }

  rule {
    api_groups = [""]
    resources  = ["pods", "pods/log", "pods/exec", "events", "configmaps", "namespaces", "nodes"]
    verbs      = ["get", "list", "watch"]
  }

  rule {
    api_groups = ["batch"]
    resources  = ["jobs", "cronjobs"]
    verbs      = ["get", "list", "watch"]
  }
}

# Task 5.6: ClusterRoleBinding for OPS group
resource "kubernetes_cluster_role_binding_v1" "namespace_ops" {
  count = var.ad_group_ops_object_id != "" ? 1 : 0

  metadata {
    name = "ops-binding"
  }

  role_ref {
    api_group = "rbac.authorization.k8s.io"
    kind      = "ClusterRole"
    name      = kubernetes_cluster_role_v1.namespace_ops.metadata[0].name
  }

  subject {
    kind      = "Group"
    name      = var.ad_group_ops_object_id
    api_group = "rbac.authorization.k8s.io"
  }
}

# --------------------------------------------------------------------------
# Task 5.7: Admin — bind to built-in cluster-admin (AC 5)
# --------------------------------------------------------------------------

resource "kubernetes_cluster_role_binding_v1" "namespace_admin" {
  count = var.ad_group_admin_object_id != "" ? 1 : 0

  metadata {
    name = "admin-binding"
  }

  role_ref {
    api_group = "rbac.authorization.k8s.io"
    kind      = "ClusterRole"
    name      = "cluster-admin"
  }

  subject {
    kind      = "Group"
    name      = var.ad_group_admin_object_id
    api_group = "rbac.authorization.k8s.io"
  }
}

