# --------------------------------------------------------------------------
# Network Policies (Task 6, 7: AC 6, 7)
# Calico is ALREADY configured on AKS (Story 1.2, IMMUTABLE)
# Policies are ADDITIVE in Calico — default-deny + explicit allow
# --------------------------------------------------------------------------

# --------------------------------------------------------------------------
# Task 6.1: Default-deny all ingress and egress per namespace (AC 6)
# --------------------------------------------------------------------------

resource "kubernetes_network_policy_v1" "default_deny" {
  for_each = var.namespaces

  metadata {
    name      = "default-deny-all"
    namespace = kubernetes_namespace_v1.namespaces[each.key].metadata[0].name
  }

  spec {
    pod_selector {}

    policy_types = ["Ingress", "Egress"]
  }
}

# --------------------------------------------------------------------------
# Task 7.1: Allow DNS egress per namespace (AC 7)
# CRITICAL: Without this, pods cannot resolve any hostnames
# --------------------------------------------------------------------------

resource "kubernetes_network_policy_v1" "allow_dns" {
  for_each = var.namespaces

  metadata {
    name      = "allow-dns"
    namespace = kubernetes_namespace_v1.namespaces[each.key].metadata[0].name
  }

  spec {
    pod_selector {}

    policy_types = ["Egress"]

    egress {
      to {
        namespace_selector {
          match_labels = {
            "kubernetes.io/metadata.name" = "kube-system"
          }
        }
      }

      ports {
        protocol = "UDP"
        port     = "53"
      }

      ports {
        protocol = "TCP"
        port     = "53"
      }
    }
  }
}

# --------------------------------------------------------------------------
# Task 7.2: Allow SAP egress per namespace (AC 7)
# Only created when SAP CIDRs are configured (per-namespace or default)
# --------------------------------------------------------------------------

locals {
  # Merge per-namespace SAP CIDRs with defaults
  namespaces_with_sap_egress = {
    for k, v in var.namespaces : k => {
      cidrs = length(v.sap_egress_cidrs) > 0 ? v.sap_egress_cidrs : var.default_sap_egress_cidrs
      ports = length(v.sap_egress_ports) > 0 ? v.sap_egress_ports : var.default_sap_egress_ports
    }
    if length(v.sap_egress_cidrs) > 0 || length(var.default_sap_egress_cidrs) > 0
  }
}

resource "kubernetes_network_policy_v1" "allow_sap_egress" {
  for_each = local.namespaces_with_sap_egress

  metadata {
    name      = "allow-sap-egress"
    namespace = kubernetes_namespace_v1.namespaces[each.key].metadata[0].name
  }

  spec {
    pod_selector {}

    policy_types = ["Egress"]

    egress {
      dynamic "to" {
        for_each = each.value.cidrs
        content {
          ip_block {
            cidr = to.value
          }
        }
      }

      dynamic "ports" {
        for_each = each.value.ports
        content {
          protocol = "TCP"
          port     = tostring(ports.value)
        }
      }
    }
  }
}

# --------------------------------------------------------------------------
# Task 7.3: Allow Azure services egress per namespace (AC 7)
# Azure DNS (168.63.129.16) and IMDS (169.254.169.254) for Workload Identity
# --------------------------------------------------------------------------

resource "kubernetes_network_policy_v1" "allow_azure_services" {
  for_each = var.namespaces

  metadata {
    name      = "allow-azure-services"
    namespace = kubernetes_namespace_v1.namespaces[each.key].metadata[0].name
  }

  spec {
    pod_selector {}

    policy_types = ["Egress"]

    # Azure DNS / metadata endpoint
    egress {
      to {
        ip_block {
          cidr = "168.63.129.16/32"
        }
      }

      ports {
        protocol = "TCP"
        port     = "443"
      }

      ports {
        protocol = "TCP"
        port     = "80"
      }
    }

    # Azure IMDS — required for Workload Identity token acquisition
    egress {
      to {
        ip_block {
          cidr = "169.254.169.254/32"
        }
      }

      ports {
        protocol = "TCP"
        port     = "80"
      }
    }
  }
}

