# --------------------------------------------------------------------------
# Resource Quotas and Limit Ranges (Task 4: AC 1)
# Per-namespace overrides via namespaces map, fallback to default variables
# --------------------------------------------------------------------------

# --------------------------------------------------------------------------
# Task 4.1: Resource Quota per namespace
# CPU: 2 req / 4 limit, Memory: 2Gi req / 4Gi limit, Pods: 20 (NFR16)
# --------------------------------------------------------------------------

resource "kubernetes_resource_quota_v1" "namespace_quotas" {
  for_each = var.namespaces

  metadata {
    name      = "namespace-quota"
    namespace = kubernetes_namespace_v1.namespaces[each.key].metadata[0].name
  }

  spec {
    hard = {
      "requests.cpu"    = coalesce(each.value.cpu_request, var.default_cpu_request)
      "limits.cpu"      = coalesce(each.value.cpu_limit, var.default_cpu_limit)
      "requests.memory" = coalesce(each.value.memory_request, var.default_memory_request)
      "limits.memory"   = coalesce(each.value.memory_limit, var.default_memory_limit)
      "pods"            = tostring(coalesce(each.value.max_pods, var.default_max_pods))
    }
  }
}

# --------------------------------------------------------------------------
# Task 4.2: Limit Range per namespace (per-container defaults)
# Default CPU: 250m req / 1 limit, Memory: 256Mi req / 1Gi limit
# Developers can override up to namespace quota limits
# --------------------------------------------------------------------------

resource "kubernetes_limit_range_v1" "namespace_limits" {
  for_each = var.namespaces

  metadata {
    name      = "default-limits"
    namespace = kubernetes_namespace_v1.namespaces[each.key].metadata[0].name
  }

  spec {
    limit {
      type = "Container"

      default_request = {
        cpu    = var.default_container_cpu_request
        memory = var.default_container_memory_request
      }

      default = {
        cpu    = var.default_container_cpu_limit
        memory = var.default_container_memory_limit
      }
    }
  }
}

