terraform {
  required_version = ">= 1.14"

  required_providers {
    azurerm = {
      source  = "hashicorp/azurerm"
      version = "~> 4.60"
    }
    kubernetes = {
      source  = "hashicorp/kubernetes"
      version = "~> 2.35"
    }
  }
}

provider "azurerm" {
  features {}
  subscription_id = var.subscription_id != "" ? var.subscription_id : null
}

# Provider alias for SAP VNet operations (cross-subscription peering).
# Uses sap_subscription_id if provided, otherwise falls back to same subscription.
provider "azurerm" {
  alias           = "sap"
  features {}
  subscription_id = var.sap_subscription_id != "" ? var.sap_subscription_id : (var.subscription_id != "" ? var.subscription_id : null)
}

# Kubernetes provider for namespace resources (Story 1.3).
# Uses kube_admin_config since local_account_disabled = true on AKS.
provider "kubernetes" {
  host                   = module.aks.kube_host
  client_certificate     = base64decode(module.aks.kube_client_certificate)
  client_key             = base64decode(module.aks.kube_client_key)
  cluster_ca_certificate = base64decode(module.aks.kube_cluster_ca_certificate)
}

